challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The AMF container has exited, causing a complete failure in the 5G core control plane. This prevents UEs from registering and accessing any services, leading to a drop in PDU sessions and all other related metrics.",
      "primary_suspect_nf": "amf",
      "probes": [
        {
          "tool": "check_process_listeners",
          "args_hint": "container='amf'",
          "expected_if_hypothesis_holds": "Command fails or returns an empty list, as the container's main process has exited and is not listening on any network sockets.",
          "falsifying_observation": "A list of listening ports is returned, indicating the AMF process is alive and running."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "nf='nr_gnb', query_spec={'metric': 'sctp_connections', 'labels': {'remote_nf': 'amf'}}",
          "expected_if_hypothesis_holds": "Value of 0, indicating the gNB has no active N2 connection to the AMF.",
          "falsifying_observation": "A value of 1 or more, indicating a healthy SCTP connection is established from the RAN to the AMF."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "nf='smf', query_spec={'metric': 'http_client_requests_total', 'labels': {'server_name': 'amf', 'status_code_class': '5xx'}}",
          "expected_if_hypothesis_holds": "A high or rapidly increasing count of 5xx errors, indicating the SMF cannot reach the AMF over the N11 interface.",
          "falsifying_observation": "A zero or stable low count of 5xx errors, suggesting the N11 interface is healthy."
        }
      ],
      "notes": "This plan focuses on directly verifying the central claim of H1 (the AMF process is dead) and then confirming the expected collateral impact on immediately adjacent components (gNB and SMF) that depend on it."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "An internal software bug or resource leak within the SMF is causing it to fail to manage PDU sessions correctly, leading to a session drop for all UEs.",
      "primary_suspect_nf": "smf",
      "probes": [
        {
          "tool": "get_nf_metrics",
          "args_hint": "nf='smf', query_spec={'metrics': ['container_cpu_usage', 'container_memory_usage']}",
          "expected_if_hypothesis_holds": "Abnormally high or steadily increasing CPU or memory usage, consistent with a software bug or resource leak.",
          "falsifying_observation": "Nominal and stable CPU and memory usage."
        },
        {
          "tool": "get_network_status",
          "args_hint": "check status of 'amf' container",
          "expected_if_hypothesis_holds": "The AMF container is in a RUNNING state. If the SMF were the true root cause, other core components like the AMF should be unaffected.",
          "falsifying_observation": "The AMF container is in an EXITED or otherwise non-running state. This would indicate a problem external to the SMF and would strongly support H1 over H2."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "nf='upf', query_spec={'metric': 'n4_session_establishment_failures'}",
          "expected_if_hypothesis_holds": "A non-zero count of N4 session establishment failures, indicating the SMF is sending invalid requests or failing to manage the UPF correctly.",
          "falsifying_observation": "A zero count for N4 session establishment failures, suggesting the SMF-UPF interface is operating correctly."
        }
      ],
      "notes": "This plan attempts to find direct evidence of the claimed SMF bug (resource leak) and its downstream impact (N4 errors). It critically includes a probe to check the status of the AMF, which serves as a powerful discriminator between H1 and H2."
    }
  ]
}

